package org.apache.spark.sql.delta;
/** Base suite containing the restore tests. */
public  interface RestoreTableSuiteBase extends org.apache.spark.sql.test.SharedSparkSession, org.apache.spark.sql.delta.test.DeltaSQLTestUtils, org.apache.spark.sql.delta.test.DeltaSQLCommandTest, org.apache.spark.sql.delta.coordinatedcommits.CatalogOwnedTestBaseSuite {
  public  long dateStringToTimestamp (java.lang.String date)  ;
  /**
   * Override the timestamp of the commit file at the given version.
   * If CC is enabled, then the timestamp generated by InCommitTimestamp will be
   * overridden since ICT is a dependent feature of CC.
   * Otherwise, the file modification time will be overridden.
   * <p>
   * NOTE: When CC is enabled, this method will only override the commit timestamp
   *       for the backfilled/published commit files.
   * <p>
   * @param deltaLog The DeltaLog for the table.
   * @param version The specific version of the commit file to override.
   * @param timestamp The timestamp to set as the commit timestamp.
   */
  public  void overrideTimestampOfCommitFile (org.apache.spark.sql.delta.DeltaLog deltaLog, int version, long timestamp)  ;
  /**
   * @param tblId            - the table identifier either table name or path
   * @param timestamp        - timestamp to restore to
   * @param isMetastoreTable - whether its a path based table or a metastore table.
   * @param expectNoOp       - whether the restore is no-op or not
   * @return (undocumented)
   */
  public  org.apache.spark.sql.Dataset<org.apache.spark.sql.Row> restoreTableToTimestamp (java.lang.String tblId, java.lang.String timestamp, boolean isMetastoreTable, boolean expectNoOp)  ;
  /**
   * @param tblId            - the table identifier either table name or path
   * @param version          - version to restore to
   * @param isMetastoreTable - whether its a path based table or metastore table
   * @param expectNoOp       - whether the restore is no-op or not
   * @return (undocumented)
   */
  public  org.apache.spark.sql.Dataset<org.apache.spark.sql.Row> restoreTableToVersion (java.lang.String tblId, int version, boolean isMetastoreTable, boolean expectNoOp)  ;
  public  void setTimestampToCommitFileAtVersion (org.apache.spark.sql.delta.DeltaLog deltaLog, int version, java.lang.String date)  ;
  public  void setTimestampToCommitFileAtVersion (org.apache.spark.sql.delta.DeltaLog deltaLog, int version, long timestamp)  ;
  public  long timeStringToTimestamp (java.lang.String time)  ;
}
